lean_obj_res lean_float_array_add(b_lean_obj_arg xs, lean_obj_arg ys) {
  lean_obj_res r;
  if (lean_is_exclusive(ys)) {
    r = ys;
  } else {
    r = lean_copy_float_array(ys);
  }

  size_t n = lean_sarray_size(r);
  const double *restrict xp = lean_float_array_cptr(xs);
  double *restrict rp = lean_float_array_cptr(r);
  for (size_t i = 0; i < n; i++) {
    rp[i] = xp[i] + rp[i];
  }
  return r;
}

lean_obj_res lean_float_array_axpy(double a, b_lean_obj_arg x, lean_obj_arg y) {
  lean_obj_res r;
  if (lean_is_exclusive(y)) {
    r = y;
  } else {
    r = lean_copy_float_array(y);
  }

  size_t n = lean_sarray_size(r);
  double *restrict rp = lean_float_array_cptr(r);
  const double *restrict xp = lean_float_array_cptr(x);
  for (size_t i = 0; i < n; i++) {
    rp[i] = rp[i] + a * xp[i];
  }
  return r;
}

double lean_float_array_sum(b_lean_obj_arg xs) {
  size_t n = lean_sarray_size(xs);
  const double *xp = lean_float_array_cptr(xs);
  double s = 0.0;
  for (size_t i = 0; i < n; i++) {
    s += xp[i];
  }
  return s;
}
